import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FaTasks, FaArrowRight, FaArrowLeft } from 'react-icons/fa';

const TaskSubmission = () => {
  const [task, setTask] = useState('');
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!task.trim()) return;

    // Mock submission - in real app, send to backend
    console.log('Task submitted:', task);
    // Navigate to AI response page with mock data
    navigate('/response', { state: { task, response: generateMockResponse(task) } });
  };

  const generateMockResponse = (userTask) => {
    // Simple mock response based on task type
    if (userTask.toLowerCase().includes('summarize')) {
      return "Here's a concise summary of your text: The provided content discusses key concepts in artificial intelligence, focusing on machine learning algorithms and their applications in modern technology. The main points cover neural networks, data processing, and future implications for various industries.";
    } else if (userTask.toLowerCase().includes('code')) {
      return "```javascript\nfunction greetUser(name) {\n  return `Hello, ${name}! Welcome to our platform.`;\n}\n\n// Usage\ngreetUser('User');\n```";
    } else {
      return "Thank you for your task submission. Our AI agent has processed your request and provided the following response: This appears to be a general inquiry. Based on the information provided, I can help you with analysis, content creation, or problem-solving tasks. Please provide more specific details for a more targeted response.";
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 p-4">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="flex items-center mb-8">
          <button
            onClick={() => navigate('/marketplace')}
            className="flex items-center text-gray-600 hover:text-gray-900 mr-4"
          >
            <FaArrowLeft className="mr-2" />
            Back to Marketplace
          </button>
        </div>

        {/* Form Card */}
        <div className="bg-white rounded-2xl shadow-xl p-8">
          <div className="text-center mb-8">
            <div className="bg-blue-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
              <FaTasks className="text-blue-600 text-3xl" />
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Submit Your Task</h1>
            <p className="text-gray-600">Describe what you need help with</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Task Description</label>
              <textarea
                value={task}
                onChange={(e) => setTask(e.target.value)}
                required
                rows={8}
                className="w-full px-6 py-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-lg"
                placeholder="Enter your task here... (e.g., 'Summarize this article about AI', 'Generate a Python function to sort a list', 'Write a blog post about blockchain technology')"
              />
            </div>

            <div className="bg-gray-50 rounded-lg p-4">
              <h3 className="font-medium text-gray-900 mb-2">Examples:</h3>
              <ul className="text-sm text-gray-600 space-y-1">
                <li>• "Summarize this text about machine learning"</li>
                <li>• "Generate Python code for a calculator"</li>
                <li>• "Write a creative story about space exploration"</li>
                <li>• "Analyze this dataset and find patterns"</li>
              </ul>
            </div>

            <button
              type="submit"
              disabled={!task.trim()}
              className="w-full bg-gradient-to-r from-blue-600 to-purple-600 text-white py-4 px-6 rounded-lg font-medium text-lg hover:from-blue-700 hover:to-purple-700 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed inline-flex items-center justify-center"
            >
              Submit Task
              <FaArrowRight className="ml-2" />
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default TaskSubmission;
